/**
 * Validates that a given host address is on the allowed local network.
 * This prevents accidentally sending cleartext traffic to non-local hosts.
 */
class LocalNetworkValidator {
    private static final String TAG = "LocalNetworkValidator";

    // Pattern matching 192.168.x.x addresses
    private static final Pattern LOCAL_IP_PATTERN =
            Pattern.compile("^192\\.168\\.\\d{1,3}\\.\\d{1,3}$");

    /**
     * Returns true if the host is a valid local network address (192.168.x.x).
     */
    static boolean isLocalNetworkHost(@NonNull String host) {
        if (!LOCAL_IP_PATTERN.matcher(host).matches()) {
            return false;
        }
        // Additional validation: ensure octets are in valid range
        try {
            String[] octets = host.split("\\.");
            for (String octet : octets) {
                int value = Integer.parseInt(octet);
                if (value < 0 || value > 255) {
                    return false;
                }
            }
            return true;
        } catch (NumberFormatException e) {
            Log.w(TAG, "Invalid IP address format: " + host);
            return false;
        }
    }

    /**
     * Validates that the host is reachable on the local network.
     */
    static boolean isHostReachable(@NonNull String host, int timeoutMs) {
        try {
            InetAddress address = InetAddress.getByName(host);
            return address.isReachable(timeoutMs);
        } catch (IOException e) {
            Log.w(TAG, "Host not reachable: " + host, e);
            return false;
        }
    }
}

/**
 * Interceptor that enforces HTTPS for cloud API requests.
 * Rejects any attempt to send cleartext traffic to non-local hosts.
 */
class HttpsEnforcementInterceptor implements Interceptor {
    private static final String TAG = "HttpsEnforcement";

    @NonNull
    @Override
    public Response intercept(@NonNull Chain chain) throws IOException {
        Request request = chain.request();
        String host = request.url().host();
        String scheme = request.url().scheme();

        // Cloud API traffic MUST use HTTPS
        if (host.equals(IoTClientConfig.CLOUD_API_HOST)) {
            if (!"https".equals(scheme)) {
                throw new IOException(
                        "Security violation: Cloud API requests must use HTTPS. " +
                                "Attempted cleartext request to: " + request.url());
            }
        }

        // Non-local hosts MUST use HTTPS
        if (!LocalNetworkValidator.isLocalNetworkHost(host) && !"https".equals(scheme)) {
            throw new IOException(
                    "Security violation: Non-local requests must use HTTPS. " +
                            "Attempted cleartext request to: " + request.url());
        }

        // Local cleartext is only allowed for verified local addresses
        if ("http".equals(scheme) && !LocalNetworkValidator.isLocalNetworkHost(host)) {
            throw new IOException(
                    "Security violation: Cleartext HTTP is only permitted for local " +
                            "network devices (192.168.x.x). Attempted request to: " + request.url());
        }

        Log.d(TAG, "Request approved: " + scheme.toUpperCase() + " to " + host);
        return chain.proceed(request);
    }
}

/**
 * Interceptor that adds common headers to all requests.
 */
class CommonHeadersInterceptor implements Interceptor {
    private final String apiKey;

    CommonHeadersInterceptor(@Nullable String apiKey) {
        this.apiKey = apiKey;
    }

    @NonNull
    @Override
    public Response intercept(@NonNull Chain chain) throws IOException {
        Request.Builder builder = chain.request().newBuilder()
                .header("User-Agent", "IoTManager-Android/1.0")
                .header("Accept", "application/json");

        // Add API key only for cloud API requests
        if (apiKey != null && chain.request().url().host().equals(IoTClientConfig.CLOUD_API_HOST)) {
            builder.header("Authorization", "Bearer " + apiKey);
        }

        return chain.proceed(builder.build());
    }
}

/**
 * Interceptor that logs certificate information for debugging TLS issues.
 * Only logs metadata, never private keys or sensitive cert data.
 */
class CertificateLoggingInterceptor implements Interceptor {
    private static final String TAG = "CertLogging";

    @NonNull
    @Override
    public Response intercept(@NonNull Chain chain) throws IOException {
        Response response = chain.proceed(chain.request());

        if (response.handshake() != null) {
            try {
                List<Certificate> certs = response.handshake().peerCertificates();
                if (!certs.isEmpty()) {
                    X509Certificate serverCert = (X509Certificate) certs.get(0);
                    Log.d(TAG, "Connected to: " + chain.request().url().host() +
                            " | Subject: " + serverCert.getSubjectDN().getName() +
                            " | Issuer: " + serverCert.getIssuerDN().getName() +
                            " | Valid until: " + serverCert.getNotAfter());
                }
            } catch (SSLPeerUnverifiedException e) {
                Log.w(TAG, "Could not verify peer certificate", e);
            }
        }

        return response;
    }
}

/**
 * Factory that creates properly configured OkHttpClient instances
 * for different target environments.
 *
 * Security design:
 * - Cloud API: HTTPS only, certificate pinning, strict TLS configuration
 * - Local secure devices: HTTPS with standard certificate validation
 * - Local legacy devices: Cleartext HTTP restricted to 192.168.x.x addresses only
 *
 * The Android network_security_config.xml provides an additional layer of defense
 * by blocking cleartext at the platform level for non-local domains.
 */
public class IoTHttpClientFactory {
    private static final String TAG = "IoTHttpClientFactory";

    private final Context context;
    private final String apiKey;

    // Cached client instances (OkHttpClient is designed to be shared)
    private volatile OkHttpClient cloudApiClient;
    private volatile OkHttpClient localSecureClient;
    private volatile OkHttpClient localLegacyClient;

    public IoTHttpClientFactory(@NonNull Context context, @Nullable String apiKey) {
        this.context = context.getApplicationContext();
        this.apiKey = apiKey;
    }

    /**
     * Returns an OkHttpClient configured for the specified target environment.
     */
    public OkHttpClient getClient(@NonNull TargetEnvironment environment) {
        switch (environment) {
            case CLOUD_API:
                return getCloudApiClient();
            case LOCAL_DEVICE_SECURE:
                return getLocalSecureClient();
            case LOCAL_DEVICE_LEGACY:
                return getLocalLegacyClient();
            default:
                throw new IllegalArgumentException("Unknown environment: " + environment);
        }
    }

    /**
     * Creates an OkHttpClient for production cloud API communication.
     * - HTTPS enforced
     * - Certificate pinning enabled
     * - Modern TLS only (TLS 1.2+)
     * - Standard certificate validation (system trust store)
     */
    private OkHttpClient getCloudApiClient() {
        if (cloudApiClient == null) {
            synchronized (this) {
                if (cloudApiClient == null) {
                    Log.i(TAG, "Creating cloud API client with certificate pinning");

                    // Certificate pinning for the production API
                    CertificatePinner certificatePinner = new CertificatePinner.Builder()
                            .add(IoTClientConfig.CLOUD_API_HOST,
                                    IoTClientConfig.CLOUD_API_PIN_PRIMARY)
                            .add(IoTClientConfig.CLOUD_API_HOST,
                                    IoTClientConfig.CLOUD_API_PIN_BACKUP)
                            .build();

                    cloudApiClient = new OkHttpClient.Builder()
                            .connectTimeout(IoTClientConfig.CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            .readTimeout(IoTClientConfig.READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            .writeTimeout(IoTClientConfig.WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            // Enforce modern TLS only
                            .connectionSpecs(Collections.singletonList(ConnectionSpec.MODERN_TLS))
                            // Pin certificates
                            .certificatePinner(certificatePinner)
                            // Enforce HTTPS — reject any cleartext attempts
                            .addInterceptor(new HttpsEnforcementInterceptor())
                            // Add common headers including auth
                            .addInterceptor(new CommonHeadersInterceptor(apiKey))
                            // Log certificate info for diagnostics
                            .addNetworkInterceptor(new CertificateLoggingInterceptor())
                            // Follow redirects only over HTTPS
                            .followSslRedirects(true)
                            .followRedirects(false) // Don't follow HTTP redirects
                            .build();
                }
            }
        }
        return cloudApiClient;
    }

    /**
     * Creates an OkHttpClient for local IoT devices that support TLS.
     * - HTTPS with standard certificate validation
     * - No certificate pinning (local devices may use self-signed certs
     *   managed via Android's trust store or network security config)
     * - Shorter timeouts for LAN responsiveness
     *
     * Note: If local devices use self-signed certificates, add them to the
     * Android trust store or configure them in network_security_config.xml
     * rather than disabling certificate validation.
     */
    private OkHttpClient getLocalSecureClient() {
        if (localSecureClient == null) {
            synchronized (this) {
                if (localSecureClient == null) {
                    Log.i(TAG, "Creating local secure device client");

                    localSecureClient = new OkHttpClient.Builder()
                            .connectTimeout(IoTClientConfig.LOCAL_CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            .readTimeout(IoTClientConfig.LOCAL_READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            .writeTimeout(IoTClientConfig.LOCAL_WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            // Allow compatible TLS for devices that may not support latest
                            .connectionSpecs(Collections.singletonList(ConnectionSpec.COMPATIBLE_TLS))
                            // Enforce HTTPS and local network validation
                            .addInterceptor(new HttpsEnforcementInterceptor())
                            // Add common headers (no API key for local devices)
                            .addInterceptor(new CommonHeadersInterceptor(null))
                            .addNetworkInterceptor(new CertificateLoggingInterceptor())
                            .build();
                }
            }
        }
        return localSecureClient;
    }

    /**
     * Creates an OkHttpClient for legacy local IoT devices that only support HTTP.
     * - Cleartext HTTP ONLY for 192.168.x.x addresses
     * - The HttpsEnforcementInterceptor validates the target is local
     * - Android network_security_config.xml provides platform-level enforcement
     * - Shorter timeouts for LAN responsiveness
     *
     * WARNING: This client allows cleartext HTTP. It must ONLY be used for
     * legacy devices on the local network that cannot be upgraded to TLS.
     * All data sent over this client is unencrypted.
     */
    private OkHttpClient getLocalLegacyClient() {
        if (localLegacyClient == null) {
            synchronized (this) {
                if (localLegacyClient == null) {
                    Log.w(TAG, "Creating legacy cleartext client — " +
                            "restricted to local network devices only");

                    localLegacyClient = new OkHttpClient.Builder()
                            .connectTimeout(IoTClientConfig.LOCAL_CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            .readTimeout(IoTClientConfig.LOCAL_READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            .writeTimeout(IoTClientConfig.LOCAL_WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                            // Allow cleartext for local legacy devices
                            .connectionSpecs(List.of(
                                    ConnectionSpec.MODERN_TLS,
                                    ConnectionSpec.COMPATIBLE_TLS,
                                    ConnectionSpec.CLEARTEXT))
                            // CRITICAL: Enforce that cleartext only goes to local addresses
                            .addInterceptor(new HttpsEnforcementInterceptor())
                            // Add common headers (no API key for local devices)
                            .addInterceptor(new CommonHeadersInterceptor(null))
                            .build();
                }
            }
        }
        return localLegacyClient;
    }

    /**
     * Checks if the device is currently connected to a WiFi network
     * (required for local device communication).
     */
    public boolean isOnLocalNetwork() {
        ConnectivityManager cm = (ConnectivityManager)
                context.getSystemService(Context.CONNECTIVITY_SERVICE);
        if (cm == null) return false;

        Network activeNetwork = cm.getActiveNetwork();
        if (activeNetwork == null) return false;

        NetworkCapabilities caps = cm.getNetworkCapabilities(activeNetwork);
        return caps != null && caps.hasTransport(NetworkCapabilities.TRANSPORT_WIFI);
    }

    /**
     * Shuts down all cached client instances and releases resources.
     */
    public synchronized void shutdown() {
        shutdownClient(cloudApiClient, "cloud API");
        shutdownClient(localSecureClient, "local secure");
        shutdownClient(localLegacyClient, "local legacy");
        cloudApiClient = null;
        localSecureClient = null;
        localLegacyClient = null;
    }

    private void shutdownClient(@Nullable OkHttpClient client, String name) {
        if (client != null) {
            client.dispatcher().executorService().shutdown();
            client.connectionPool().evictAll();
            if (client.cache() != null) {
                try {
                    client.cache().close();
                } catch (IOException e) {
                    Log.w(TAG, "Error closing " + name + " client cache", e);
                }
            }
            Log.i(TAG, "Shut down " + name + " client");
        }
    }
}

