package com.iotmanager.network;

import android.content.Context;
import android.util.Log;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;

import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.io.IOException;

import okhttp3.MediaType;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;
import okhttp3.ResponseBody;

/**
 * High-level API service for IoT device management.
 * Handles both cloud API and local device communication
 * with appropriate security for each context.
 */
public class IoTDeviceApiService {
    private static final String TAG = "IoTDeviceApiService";
    private static final MediaType JSON = MediaType.get("application/json; charset=utf-8");

    private final IoTHttpClientFactory clientFactory;

    public IoTDeviceApiService(@NonNull Context context, @NonNull String apiKey) {
        this.clientFactory = new IoTHttpClientFactory(context, apiKey);
    }

    // ========================================
    // Cloud API Methods (always HTTPS + pinned)
    // ========================================

    /**
     * Fetches the list of registered devices from the cloud API.
     * Uses HTTPS with certificate pinning.
     */
    @NonNull
    public String getRegisteredDevices() throws IOException {
        OkHttpClient client = clientFactory.getClient(TargetEnvironment.CLOUD_API);

        Request request = new Request.Builder()
                .url(IoTClientConfig.CLOUD_API_BASE_URL + "/devices")
                .get()
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful()) {
                throw new IOException("Cloud API error: " + response.code() + " " + response.message());
            }
            ResponseBody body = response.body();
            return body != null ? body.string() : "";
        }
    }

    /**
     * Registers a new device with the cloud API.
     * Uses HTTPS with certificate pinning.
     */
    @NonNull
    public String registerDevice(@NonNull String deviceName, @NonNull String deviceType,
                                 @NonNull String macAddress) throws IOException, JSONException {
        OkHttpClient client = clientFactory.getClient(TargetEnvironment.CLOUD_API);

        JSONObject payload = new JSONObject();
        payload.put("name", deviceName);
        payload.put("type", deviceType);
        payload.put("mac_address", macAddress);

        Request request = new Request.Builder()
                .url(IoTClientConfig.CLOUD_API_BASE_URL + "/devices")
                .post(RequestBody.create(payload.toString(), JSON))
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful()) {
                throw new IOException("Device registration failed: " + response.code());
            }
            ResponseBody body = response.body();
            return body != null ? body.string() : "";
        }
    }

    /**
     * Sends device telemetry data to the cloud API.
     * Uses HTTPS with certificate pinning.
     */
    public void sendTelemetry(@NonNull String deviceId, @NonNull JSONObject telemetryData)
            throws IOException, JSONException {
        OkHttpClient client = clientFactory.getClient(TargetEnvironment.CLOUD_API);

        JSONObject payload = new JSONObject();
        payload.put("device_id", deviceId);
        payload.put("timestamp", System.currentTimeMillis());
        payload.put("data", telemetryData);

        Request request = new Request.Builder()
                .url(IoTClientConfig.CLOUD_API_BASE_URL + "/telemetry")
                .post(RequestBody.create(payload.toString(), JSON))
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful()) {
                throw new IOException("Telemetry upload failed: " + response.code());
            }
        }
    }

    // ========================================
    // Local Device Methods
    // ========================================

    /**
     * Queries a local IoT device for its status.
     * Automatically selects HTTPS or HTTP based on device capabilities.
     *
     * @param deviceIp   The local IP address (must be 192.168.x.x)
     * @param port       The device port
     * @param supportsTls Whether the device supports TLS
     */
    @NonNull
    public String getLocalDeviceStatus(@NonNull String deviceIp, int port,
                                       boolean supportsTls) throws IOException {
        validateLocalAddress(deviceIp);
        validateLocalNetworkAvailable();

        TargetEnvironment env = supportsTls
                ? TargetEnvironment.LOCAL_DEVICE_SECURE
                : TargetEnvironment.LOCAL_DEVICE_LEGACY;
        OkHttpClient client = clientFactory.getClient(env);

        String scheme = supportsTls ? "https" : "http";
        String url = scheme + "://" + deviceIp + ":" + port + "/api/status";

        if (!supportsTls) {
            Log.w(TAG, "Using cleartext HTTP for legacy device at " + deviceIp +
                    " — data is not encrypted. Consider upgrading device firmware.");
        }

        Request request = new Request.Builder()
                .url(url)
                .get()
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful()) {
                throw new IOException("Local device error: " + response.code());
            }
            ResponseBody body = response.body();
            return body != null ? body.string() : "";
        }
    }

    /**
     * Sends a command to a local IoT device.
     *
     * @param deviceIp    The local IP address (must be 192.168.x.x)
     * @param port        The device port
     * @param supportsTls Whether the device supports TLS
     * @param command     The command to send
     * @param parameters  Optional command parameters
     */
    @NonNull
    public String sendLocalDeviceCommand(@NonNull String deviceIp, int port,
                                         boolean supportsTls, @NonNull String command,
                                         @Nullable JSONObject parameters)
            throws IOException, JSONException {
        validateLocalAddress(deviceIp);
        validateLocalNetworkAvailable();

        TargetEnvironment env = supportsTls
                ? TargetEnvironment.LOCAL_DEVICE_SECURE
                : TargetEnvironment.LOCAL_DEVICE_LEGACY;
        OkHttpClient client = clientFactory.getClient(env);

        String scheme = supportsTls ? "https" : "http";
        String url = scheme + "://" + deviceIp + ":" + port + "/api/command";

        if (!supportsTls) {
            Log.w(TAG, "Sending command over cleartext HTTP to legacy device at " + deviceIp);
        }

        JSONObject payload = new JSONObject();
        payload.put("command", command);
        if (parameters != null) {
            payload.put("parameters", parameters);
        }

        Request request = new Request.Builder()
                .url(url)
                .post(RequestBody.create(payload.toString(), JSON))
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful()) {
                throw new IOException("Command failed: " + response.code());
            }
            ResponseBody body = response.body();
            return body != null ? body.string() : "";
        }
    }

    /**
     * Discovers IoT devices on the local network by scanning common ports.
     * Uses HTTPS first, falls back to HTTP for legacy devices.
     *
     * @param deviceIp The local IP address to probe
     * @param port     The port to check
     * @return Device info JSON string, or null if no device found
     */
    @Nullable
    public String discoverLocalDevice(@NonNull String deviceIp, int port) {
        validateLocalAddress(deviceIp);

        // Try HTTPS first (preferred)
        try {
            OkHttpClient secureClient = clientFactory.getClient(TargetEnvironment.LOCAL_DEVICE_SECURE);
            Request request = new Request.Builder()
                    .url("https://" + deviceIp + ":" + port + "/api/info")
                    .get()
                    .build();

            try (Response response = secureClient.newCall(request).execute()) {
                if (response.isSuccessful()) {
                    Log.i(TAG, "Discovered TLS-capable device at " + deviceIp + ":" + port);
                    ResponseBody body = response.body();
                    return body != null ? body.string() : null;
                }
            }
        } catch (IOException e) {
            Log.d(TAG, "HTTPS probe failed for " + deviceIp + ":" + port +
                    ", trying HTTP for legacy device");
        }

        // Fall back to HTTP for legacy devices (local network only)
        try {
            OkHttpClient legacyClient = clientFactory.getClient(TargetEnvironment.LOCAL_DEVICE_LEGACY);
            Request request = new Request.Builder()
                    .url("http://" + deviceIp + ":" + port + "/api/info")
                    .get()
                    .build();

            try (Response response = legacyClient.newCall(request).execute()) {
                if (response.isSuccessful()) {
                    Log.w(TAG, "Discovered legacy (HTTP-only) device at " + deviceIp + ":" + port);
                    ResponseBody body = response.body();
                    return body != null ? body.string() : null;
                }
            }
        } catch (IOException e) {
            Log.d(TAG, "HTTP probe also failed for " + deviceIp + ":" + port);
        }

        return null;
    }

    // ========================================
    // Validation Helpers
    // ========================================

    /**
     * Validates that the given IP is a local network address.
     * Throws IllegalArgumentException if not.
     */
    private void validateLocalAddress(@NonNull String deviceIp) {
        if (!LocalNetworkValidator.isLocalNetworkHost(deviceIp)) {
            throw new IllegalArgumentException(
                    "Security error: " + deviceIp + " is not a valid local network address. " +
                            "Only 192.168.x.x addresses are permitted for local device communication.");
        }
    }

    /**
     * Validates that the device is connected to a local WiFi network.
     */
    private void validateLocalNetworkAvailable() {
        if (!clientFactory.isOnLocalNetwork()) {
            Log.w(TAG, "Device may not be on a local WiFi network. " +
                    "Local device communication may fail.");
        }
    }

    /**
     * Releases all resources held by this service.
     */
    public void shutdown() {
        clientFactory.shutdown();
    }
}